### зј“еӯҳ ```sql -- create table CREATE UNLOGGED TABLE cache ( key TEXT PRIMARY KEY, value JSONB NOT NULL, expires_at TIMESTAMPTZ NOT NULL );
CREATE INDEX idx_cache_expires ON cache(expires_at);
-- insert INSERT INTO cache (key, value, expires_at) VALUES ($1, $2, NOW() + INTERVAL '1 hour') ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, expires_at = EXCLUDED.expires_at;
-- read SELECT value FROM cache WHERE key = $1 AND expires_at > NOW();
-- cleanup DELETE FROM cache WHERE expires_at < NOW(); ```
### и®ўйҳ… ```sql NOTIFY notifications, '{'userId': 123, 'msg': 'Hello'}';
LISTEN notifications; ```
### д»»еҠЎйҳҹеҲ— ```sql -- create table CREATE TABLE jobs ( id BIGSERIAL PRIMARY KEY, queue TEXT NOT NULL, payload JSONB NOT NULL, attempts INT DEFAULT 0, max_attempts INT DEFAULT 3, scheduled_at TIMESTAMPTZ DEFAULT NOW(), created_at TIMESTAMPTZ DEFAULT NOW() );
CREATE INDEX idx_jobs_queue ON jobs(queue, scheduled_at) WHERE attempts < max_attempts;
-- insert INSERT INTO jobs (queue, payload) VALUES ('send-email', '{'to': 'user@example.com', 'subject': 'Hi'}');
-- select WITH next_job AS ( SELECT id FROM jobs WHERE queue = $1 AND attempts < max_attempts AND scheduled_at <= NOW() ORDER BY scheduled_at LIMIT 1 FOR UPDATE SKIP LOCKED ) UPDATE jobs SET attempts = attempts + 1 FROM next_job WHERE jobs.id = next_job.id RETURNING *; ```
### йҖҹзҺҮйҷҗеҲ¶ ```sql CREATE TABLE rate_limits ( user_id INT PRIMARY KEY, request_count INT DEFAULT 0, window_start TIMESTAMPTZ DEFAULT NOW() );
-- Check and increment WITH current AS ( SELECT request_count, CASE WHEN window_start < NOW() - INTERVAL '1 minute' THEN 1 -- Reset counter ELSE request_count + 1 END AS new_count FROM rate_limits WHERE user_id = $1 FOR UPDATE ) UPDATE rate_limits SET request_count = (SELECT new_count FROM current), window_start = CASE WHEN window_start < NOW() - INTERVAL '1 minute' THEN NOW() ELSE window_start END WHERE user_id = $1 RETURNING request_count;
-- window function CREATE TABLE api_requests ( user_id INT NOT NULL, created_at TIMESTAMPTZ DEFAULT NOW() );
-- Check rate limit SELECT COUNT(*) FROM api_requests WHERE user_id = $1 AND created_at > NOW() - INTERVAL '1 minute';
-- If under limit, insert INSERT INTO api_requests (user_id) VALUES ($1);
-- Cleanup old requests periodically DELETE FROM api_requests WHERE created_at < NOW() - INTERVAL '5 minutes'; ```
### з”ЁжҲ·дјҡиҜқ ```sql CREATE TABLE sessions ( id TEXT PRIMARY KEY, data JSONB NOT NULL, expires_at TIMESTAMPTZ NOT NULL );
CREATE INDEX idx_sessions_expires ON sessions(expires_at);
-- Insert/Update INSERT INTO sessions (id, data, expires_at) VALUES ($1, $2, NOW() + INTERVAL '24 hours') ON CONFLICT (id) DO UPDATE SET data = EXCLUDED.data, expires_at = EXCLUDED.expires_at;
-- Read SELECT data FROM sessions WHERE id = $1 AND expires_at > NOW(); ```
жқҘжәҗ [I Replaced Redis with PostgreSQL (And It's Faster)](https://dev.to/polliog/i-replaced-redis-with-postgresql-and-its-faster-4942) гҖӮ

еҶҷдәҶдёҖдёӘеҺ»йҷӨ `map` дёӯзҡ„йӣ¶ж•°еҖјзҡ„ж–№жі•пјҢеҰӮдёӢжүҖзӨәпјҢ  
еҸ‘зҺ°еҪ“жңүдәӣеҖјдёә `int64` зұ»еһӢж—¶пјҢеҚідҪҝдёәйӣ¶ж•°еҖјд№ҹдёҚдјҡеҺ»йҷӨпјҢ

```go
func RemoveMapZeroNumValue(m map[string]interface{}, excludeKeysMap map[string]struct{}) map[string]interface{} {
	for k, v := range m {
		if _, ok := excludeKeysMap[k]; ok {
			continue
		}
		switch val := v.(type) {
		case int, int8, int16, int32, int64,
			uint, uint8, uint16, uint32, uint64,
			float32, float64:
			if val == 0 || val == 0.0 {
				delete(m, k)
			}
		}
	}
	return m
}
```

еҺҹжқҘGo зҡ„еӨҡзұ»еһӢ case дёҚдјҡжҠҠ val зҡ„зұ»еһӢз»ҹдёҖпјҢе®ғеҸӘдҝқиҜҒдҪ иҝӣе…ҘдәҶиҝҷдёӘ caseпјҢ
Go зҡ„ type switch и§„еҲҷпјҡ
- val зҡ„йқҷжҖҒзұ»еһӢдёәжүҖжңү case зҡ„гҖҢе…¬е…ұзұ»еһӢгҖҚ
- еӨҡдёӘзұ»еһӢзҡ„е…¬е…ұзұ»еһӢе°ұжҳҜ interface{}
- жүҖд»Ҙ val зҡ„йқҷжҖҒзұ»еһӢжҳҜ interface{}

еҶҷжі• | val зҡ„е®һйҷ…зұ»еһӢ | жҜ”иҫғз»“жһң
-- | -- | --
case int: | int | val == 0 жӯЈеёё
case int, float64: | interface{} | val == 0 ж°ёиҝң false

и§ЈеҶіж–№жі•пјҡ
1. дҪҝз”Ё `reflect.ValueOf(val).IsZero()` еҲӨж–ӯ
2. жӢҶеҲҶжүҖжңү case гҖӮ

йҖҡиҝҮ [gorm clickhouse](https://github.com/go-gorm/clickhouse) иҝӣиЎҢжү№йҮҸж•°жҚ®жҸ’е…Ҙж—¶пјҢеҰӮжһңи¶…иҝҮжү№еӨ§е°ҸпјҢе°ұдјҡжҠҘд»ҘдёӢй”ҷиҜҜпјҢ

```
[clickhouse][conn=1][127.0.0.1:9000][exception] code: 101, message: Unexpected packet Query received from client
[clickhouse-std][conn=0][127.0.0.1:9000] PrepareContext error: code: 101, message: Unexpected packet Query received from client
```

жөӢиҜ•д»Јз ҒеҰӮдёӢпјҢ

```go
package main

import (
	'crypto/md5'
	'fmt'
	'io'
	'time'

	std_ck 'github.com/ClickHouse/clickhouse-go/v2'
	'gorm.io/datatypes'
	'gorm.io/driver/clickhouse'
	'gorm.io/gorm'
)

type AdTencentReportCK struct {
	AppID      int64  `json:'app_id'`                            // funnydb еә”з”ЁID
	ReportID   string `json:'report_id'`                         // жҠҘиЎЁID
	ReportType string `json:'report_type'`                       // жҠҘиЎЁзұ»еһӢ
	Level      string `json:'level'`                             // жҠҘиЎЁзұ»еһӢзә§еҲ«
	TimeLine   string `json:'time_line'`                         // ж—¶й—ҙеҸЈеҫ„
	AccountId  int64  `json:'account_id'`                        // иҙҰеҸ·ID
	Date       string `json:'date'`                              // ж—Ҙжңҹ
	Hour       int64  `json:'hour'`                              // е°Ҹж—¶(0-23)
	IngestTime int64  `json:'ingest_time' gorm:'autoCreateTime'` // йҮҮйӣҶж—¶й—ҙпјҢжҜ«з§’зә§
	Data       datatypes.JSON
}

func (AdTencentReportCK) TableName() string {
	return 'ad_tencent_reports_test'
}

func GenerateReportID(keys ...string) string {
	w := md5.New()
	for _, key := range keys {
		_, _ = io.WriteString(w, key)
	}
	return fmt.Sprintf('%x', w.Sum(nil))
}

func main() {
	ckSTDDB := std_ck.OpenDB(&std_ck.Options{
		Addr: []string{'127.0.0.1:9000'},
		Auth: std_ck.Auth{
			Database: 'ad_reports',
			Username: 'admin',
			Password: 'secret',
		},
		Settings: std_ck.Settings{
			'max_execution_time': 3600,
			'final':              1,
		},
		DialTimeout: 5 * time.Second,
		Compression: &std_ck.Compression{
			Method: std_ck.CompressionLZ4,
		},
		Debug: true,
	})

	ckDB, err := gorm.Open(clickhouse.New(clickhouse.Config{
		Conn: ckSTDDB,
	}))
	if err != nil {
		panic(err)
	}

	var reports []*AdTencentReportCK
	for i := 0; i < 110; i++ {
		report := AdTencentReportCK{
			AppID:      1,
			ReportID:   GenerateReportID('1', fmt.Sprintf('%d', i+1)),
			ReportType: 'daily_reports',
			Level:      'REPORT_LEVEL_ADVERTISER',
			TimeLine:   'ACTIVE_TIME',
			AccountId:  int64(i + 1),
			Date:       '2025-01-01',
			IngestTime: 1763308800,
			Data:       datatypes.JSON(`{'cost': 1000}`),
		}
		reports = append(reports, &report)
	}

	if err := ckDB.CreateInBatches(reports, 100).Error; err != nil {
		panic(err)
	}
}
```

и§ЈеҶіж–№ејҸпјҢзӣҙжҺҘдҪҝз”ЁпјҢ
```go
if err := ckDB.Create(reports).Error; err != nil {
	panic(err)
}
```

### жіЁж„ҸдәӢйЎ№
еңЁеҗҢдёҖдёӘдәӢеҠЎдёӯеӨҡж¬ЎжҸҗдәӨд№ҹдјҡи§ҰеҸ‘иҝҷдёӘй”ҷиҜҜпјҢжҜ”еҰӮ
```go
if err := ckDB.Transaction(func(tx *gorm.DB) error {
	for _, _reports := range reports {
		if err := tx.Create(_reports).Error; err != nil {
			return err
		}
	}
	return nil
}); err != nil {
	panic(err)
}
```гҖӮ

### ж•°жҚ®з»“жһ„ ```go // и§„еҲҷ type ScheduleRule struct { ID int64 // и§„еҲҷID Title string // и§„еҲҷж Үйўҳ Payload string // и§„еҲҷеҶ…е®№ Enabled bool // и§„еҲҷејҖе…і StartTime time.Time // ејҖе§Ӣж—¶й—ҙ EndTime time.Time // з»“жқҹж—¶й—ҙ NextCheckTime sql.NullTime // дёӢж¬ЎжЈҖжҹҘж—¶й—ҙ CheckFrequency string // жЈҖжҹҘйў‘зҺҮ }
// д»»еҠЎ type RuleTask struct { ID int64 // д»»еҠЎID RuleID int64 // и§„еҲҷID RunTime time.Time // ејҖе§Ӣж—¶й—ҙ Payload string // и§„еҲҷеҶ…е®№ Status string // д»»еҠЎзҠ¶жҖҒ Result string // д»»еҠЎз»“жһң } ```
### жіЁж„ҸдәӢйЎ№ 1. ж”№ејҖе§Ӣж—¶й—ҙпјҢдёҚиғҪж—©дәҺеҪ“еүҚж—¶й—ҙпјҢйҮҚж–°и®Ўз®— next_check_time 2. ж”№з»“жқҹж—¶й—ҙпјҢдёҚиғҪж—©дәҺеҪ“еүҚж—¶й—ҙпјҢзӣҙжҺҘдҝ®ж”№ 3. ж”№жЈҖжҹҘйў‘зҺҮпјҢйҮҚж–°и®Ўз®— next_check_time 4. ж”№и§„еҲҷејҖе…іпјҢеҰӮжһңејҖеҗҜпјҢйҮҚж–°и®Ўз®— next_check_time 5. next_check_time дёәи·қзҰ»еҪ“еүҚж—¶й—ҙжңҖиҝ‘зҡ„дёӢдёҖж¬Ўжү§иЎҢж—¶й—ҙ 6. з”ҹжҲҗд»»еҠЎе’Ңзј–иҫ‘и§„еҲҷж—¶еқҮйңҖиҰҒй”Ғе®ҡи§„еҲҷпјҢйҳІжӯўе№¶еҸ‘гҖӮ

