и®°еҪ•дёҖдёӢеҰӮдҪ•дҪҝз”Ё gorm е®һзҺ°д»»ж„ҸеұӮзә§зҡ„ж–Үд»¶еӨ№жЁЎеһӢпјҢд»Јз ҒеҰӮдёӢ


```go
type AdFolder struct {
	ID        uint64 `gorm:'primarykey'`           // ж•°жҚ®еә“ID
	CreatedAt int64  `gorm:'autoCreateTime:milli'` // и®°еҪ•еҲӣе»әж—¶й—ҙпјҢеҚ•дҪҚ milli
	UpdatedAt int64  `gorm:'autoUpdateTime:milli'` // и®°еҪ•жӣҙж–°ж—¶й—ҙпјҢеҚ•дҪҚ milli

	AppID       uint64 `gorm:'index:idx_ad_folders_type'` // еә”з”ЁID
	Type        string `gorm:'index:idx_ad_folders_type'` // еҲҶзұ»зұ»еһӢ
	Title       string // ж Үйўҳ
	Description string // иҜҙжҳҺ
	ParentID    uint64 `gorm:'index'` // зҲ¶ж–Үд»¶еӨ№ID
	RootID      uint64 `gorm:'index'` // ж №ж–Үд»¶еӨ№ID

	CreatorID    uint64 // еҲӣе»әз”ЁжҲ·ID
	LastEditorID uint64 // жңҖеҗҺзј–иҫ‘з”ЁжҲ·ID

	Parent      *AdFolder   `gorm:'foreignKey:ParentID'` // зҲ¶иҠӮзӮ№
	Children    []*AdFolder `gorm:'foreignKey:ParentID'` // зӣҙзі»еӯҗиҠӮзӮ№
	Root        *AdFolder   `gorm:'foreignKey:RootID'`   // ж №иҠӮзӮ№
	Descendants []*AdFolder `gorm:'foreignKey:RootID'`   // ж №зі»еӯҗиҠӮзӮ№
}


// иҺ·еҸ–ж №ж–Үд»¶еӨ№ID
func (a *AdFolder) GetFolderRootID() uint64 {
	var rootID uint64
	if a.RootID != 0 {
		rootID = a.RootID
	} else if a.ID != 0 {
		rootID = a.ID
	}
	return rootID
}

// иҺ·еҸ–зӣёеҗҢж №иҠӮзӮ№зҡ„ж–Үд»¶еӨ№еҲ—иЎЁ
func (a *AdFolder) GetSameRootAdFolders(tx *gorm.DB) ([]*AdFolder, error) {
	var adFolders []*AdFolder
	query := tx.Model(&AdFolder{}).
		Where('app_id = ?', a.AppID).
		Where('type = ?', a.Type)
	if a.RootID == 0 {
		query = query.Where('(id = ? OR root_id = ?)', a.ID, a.ID)
	} else {
		query = query.Where('(id = ? OR root_id = ?)', a.RootID, a.RootID)
	}
	if err := query.Order('id DESC').
		Find(&adFolders).Error; err != nil {
		return nil, err
	}
	return adFolders, nil
}

// жһ„йҖ ж–Үд»¶еӨ№зҲ¶иҠӮзӮ№ж•°з»„
func (a *AdFolder) GetAdFolderParents(tx *gorm.DB) ([]*AdFolder, error) {
	adFolders, err := a.GetSameRootAdFolders(tx)
	if err != nil {
		return nil, err
	}
	adFoldersMap := make(map[uint64]*AdFolder, len(adFolders))
	parentAdFoldersMap := make(map[uint64]uint64, len(adFolders)) // children : parent
	for _, folder := range adFolders {
		adFoldersMap[folder.ID] = folder
		if folder.ParentID != 0 {
			parentAdFoldersMap[folder.ID] = folder.ParentID
		}
	}

	var parents []*AdFolder
	currentID := a.ID
	for {
		parentID, exists := parentAdFoldersMap[currentID]
		if !exists {
			break
		}

		parent, ok := adFoldersMap[parentID]
		if !ok {
			break
		}

		parents = append([]*AdFolder{parent}, parents...)
		currentID = parentID
	}
	return parents, nil
}

// жһ„йҖ ж–Үд»¶еӨ№ж ‘еҪўз»“жһ„
func BuildAdFolderTree(adFolders []*AdFolder) []*AdFolder {
	adFoldersMap := make(map[uint64]*AdFolder, len(adFolders))
	for _, adFolder := range adFolders {
		adFoldersMap[adFolder.ID] = adFolder
	}

	var roots []*AdFolder
	for _, adFolder := range adFolders {
		if adFolder.ParentID == 0 {
			roots = append(roots, adFolder)
		} else {
			if parent, ok := adFoldersMap[adFolder.ParentID]; ok {
				parent.Children = append(parent.Children, adFolder)
				adFoldersMap[adFolder.ParentID] = parent
			}
		}
	}
	return roots
}

// еҜ»жүҫжүҖжңүеҗҺд»ЈиҠӮзӮ№
func (a *AdFolder) GetAdFolderDescendants(tx *gorm.DB) ([]*AdFolder, error) {
	adFolders, err := a.GetSameRootAdFolders(tx)
	if err != nil {
		return nil, err
	}
	adFoldersMap := make(map[uint64]*AdFolder)
	childrenMap := make(map[uint64][]uint64)

	for _, adFolder := range adFolders {
		adFoldersMap[adFolder.ID] = adFolder
		if adFolder.ParentID != 0 {
			childrenMap[adFolder.ParentID] = append(childrenMap[adFolder.ParentID], adFolder.ID)
		}
	}

	var children []*AdFolder
	queue := []uint64{a.ID}
	for len(queue) > 0 {
		currentID := queue[0]
		queue = queue[1:]
		for _, childID := range childrenMap[currentID] {
			if child, exists := adFoldersMap[childID]; exists {
				children = append(children, child)
				queue = append(queue, childID)
			}
		}
	}
	return children, nil
}
```гҖӮ

йҖҡиҝҮ `postgres` зҡ„ж•°жҚ®еә“иЎҢзә§еҲ«зҡ„й”ҒжңәеҲ¶е…ЁеұҖжҺ§еҲ¶жүҖжңүзҡ„д»»еҠЎеҸӘеңЁжҹҗдёӘиҠӮзӮ№дёҠжү§иЎҢ

```go
package main

import (
	'context'
	'errors'
	'log'
	'time'

	'github.com/jackc/pgconn'
	'golang.org/x/sync/errgroup'
	'gorm.io/driver/postgres'
	'gorm.io/gorm'
	'gorm.io/gorm/clause'
	'gorm.io/gorm/logger'
)

const (
	globalJobLockGetPollingDuration = time.Second // е…ЁеұҖд»»еҠЎй”ҒиҪ®иҜўж—¶й—ҙ

	ServiceDeploymentNameGlobalJobLock = 'global-job-lock' // е…ЁеұҖд»»еҠЎй”Ғ
)

type ServiceDeployment struct {
	Name string `gorm:'primarykey'` // жңҚеҠЎеҗҚз§°

	CreatedAt int64 `gorm:'autoCreateTime:milli'` // и®°еҪ•еҲӣе»әж—¶й—ҙпјҢеҚ•дҪҚ milli
	UpdatedAt int64 `gorm:'autoUpdateTime:milli'` // и®°еҪ•жӣҙж–°ж—¶й—ҙпјҢеҚ•дҪҚ milli
}

func main() {
	dsn := 'host=localhost user=postgres password=secret dbname=test port=5432 sslmode=disable'
	db, err := gorm.Open(postgres.Open(dsn), &gorm.Config{})
	if err != nil {
		log.Fatal(err)
	}
	if err := db.AutoMigrate(&ServiceDeployment{}); err != nil {
		log.Fatal(err)
	}

	var jobEnable bool

	eg, ctx := errgroup.WithContext(context.Background())
	eg.Go(func() error {
		ticker := time.NewTicker(globalJobLockGetPollingDuration)
		defer ticker.Stop()

		for {
			exist, err := GetGlobalJobLock(db)
			if err != nil {
				log.Println(err)
			}
			if exist {
				jobEnable = true
				break
			}

			select {
			case <-ctx.Done():
				return ctx.Err()
			case <-ticker.C:
			}
		}
		return nil
	})

	eg.Go(func() error {
		if err := stopTickerUntil(ctx, globalJobLockGetPollingDuration, func() bool {
			return jobEnable
		}); err != nil {
			return err
		}
		return RunJob(ctx)
	})

	if err := eg.Wait(); err != nil {
		log.Println(err)
	}
}

func FindOne(db *gorm.DB, out interface{}) (bool, error) {
	result := db.First(out)
	if err := result.Error; err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return false, nil
		}
		return false, err
	}
	return true, nil
}

func GetGlobalJobLock(db *gorm.DB) (bool, error) {
	deployment := ServiceDeployment{
		Name: ServiceDeploymentNameGlobalJobLock,
	}
	if err := db.FirstOrCreate(&deployment, ServiceDeployment{Name: ServiceDeploymentNameGlobalJobLock}).Error; err != nil {
		return false, err
	}

	tx := db.Session(&gorm.Session{Logger: logger.Discard}).Begin() // дёҚжү“еҚ°й”ҷиҜҜж—Ҙеҝ—пјҢжӢҝеҲ°й”ҒдјҡеҚ з”ЁдёҖдёӘж•°жҚ®еә“иҝһжҺҘ
	exist, err := FindOne(tx.Clauses(clause.Locking{Strength: 'UPDATE', Options: 'NOWAIT'}).Where('name = ?', ServiceDeploymentNameGlobalJobLock), &deployment)
	if err != nil {
		if pgErr, ok := err.(*pgconn.PgError); ok && pgErr.Code == '55P03' {
			err = nil
		}
		_ = tx.Rollback()
	}
	return exist, err
}

func stopTickerUntil(ctx context.Context, duration time.Duration, stopFunc func() bool) error {
	ticker := time.NewTicker(duration)
	defer ticker.Stop()

Loop:
	for {
		select {
		case <-ctx.Done():
			return ctx.Err()
		case <-ticker.C:
			if stopFunc() {
				break Loop
			}
		}
	}
	return nil
}

func RunJob(ctx context.Context) error {
	// run job
	return nil
}
